mapper.insert:
insert into dayk (code, day, name, open, high, low, `close`, prev_close, percent, volume, amount, turnover_rate, ma5, ma10, ma20, ma30, ma60, ma120, dea, dif, macd, cross_params, create_time, update_time)
values (#{code}, #{day}, #{name}, #{open}, #{high}, #{low}, #{close}, #{prevClose}, #{percent}, #{volume}, #{amount}, #{turnoverRate}
  , #{ma5}, #{ma10}, #{ma20}, #{ma30}, #{ma60}, #{ma120}, #{dea}, #{dif}, #{macd}, #{crossParams}, now(), now())

mapper.update:
update dayk set update_time = now()

       , name = #{name}


       , open = #{open}


       , high = #{high}


       , low = #{low}


       , `close` = #{close}


       , prev_close = #{prevClose}


       , percent = #{percent}


       , volume = #{volume}


       , amount = #{amount}


       , turnover_rate = #{turnoverRate}


       , ma5 = #{ma5}


       , ma10 = #{ma10}


       , ma20 = #{ma20}


       , ma30 = #{ma30}


       , ma60 = #{ma60}


       , ma120 = #{ma120}


       , dea = #{dea}


        , dif = #{dif}


       , macd = #{macd}


       , cross_params = #{crossParams}

where code = #{code} and day = #{day}

mapper.select:
   	select d.code, d.day, d.open, d.`close`, d.prev_close, d.high, d.low, d.ma5, d.ma10, d.ma20, d.ma30, d.ma60, d.ma120, d.dea, d.dif, d.macd, d.cross_params, d.amount, d.volume from dayk d


		  		and d.code = #{code}



				and (select count(*) from dayk where code=d.code and day > d.day) < #{ndays}

select d.* from dayk d where
d.code = #{code} and d.day < #{fromDay}
order by d.day desc limit 1
